SELECT d.id, d.parent_id, d.dept_name, d.dept_code, d.dept_type, d.status, d.visible, d.sort, d.leader_id, d.leader_name, d.leader_phone, d.leader_email, d.phone, d.email, d.address, d.description, d.is_system, d.is_deletable, d.is_editable, d.dept_icon, d.dept_color, d.ext_data, d.create_time, d.update_time, d.create_by, d.update_by, d.remark, p.dept_name as parent_name, COUNT(DISTINCT u.id) as user_count, COUNT(DISTINCT r.id) as role_count FROM sys_dept d LEFT JOIN sys_dept p ON d.parent_id = p.id LEFT JOIN sys_user u ON d.id = u.dept_id AND u.deleted = 0 LEFT JOIN sys_role_dept rd ON d.id = rd.dept_id LEFT JOIN sys_role r ON rd.role_id = r.id AND r.deleted = 0
d.deleted = 0
AND d.dept_name LIKE CONCAT('%', #{query.deptName}, '%')
AND d.dept_code LIKE CONCAT('%', #{query.deptCode}, '%')
AND d.dept_type = #{query.deptType}
AND d.status = #{query.status}
AND d.visible = #{query.visible}
AND d.parent_id = #{query.parentId}
AND d.leader_name LIKE CONCAT('%', #{query.leaderName}, '%')
AND d.leader_phone LIKE CONCAT('%', #{query.leaderPhone}, '%')
AND d.leader_email LIKE CONCAT('%', #{query.leaderEmail}, '%')
AND d.phone LIKE CONCAT('%', #{query.phone}, '%')
AND d.email LIKE CONCAT('%', #{query.email}, '%')
AND d.is_system = #{query.isSystem}
AND d.create_time >= #{query.startTime}
AND d.create_time <= #{query.endTime}
GROUP BY d.id ORDER BY d.sort ASC, d.create_time DESC

